{
  "version": 1,
  "project": {
    "prefix": "CART",
    "name": "cartographer"
  },
  "stack": {
    "primary": [
      "typescript",
      "node",
      "commander",
      "lowdb",
      "ink",
      "react",
      "chalk"
    ],
    "test": "vitest",
    "build": "tsc",
    "lint": "eslint"
  },
  "commands": {
    "test": "vitest run",
    "build": "tsc",
    "lint": "eslint src"
  },
  "paths": {
    "workflows": ".forge/workflows",
    "engineering": "engineering",
    "store": ".forge/store",
    "templates": ".forge/templates",
    "commands": ".claude/commands/cart"
  },
  "mode": "full",
  "installedSkills": []
}

export interface Node {
  id: string;
  title: string;
  body: string;
  tags: string[];
  createdAt: string;
  updatedAt: string;
}

export interface Edge {
  from: string;
  to: string;
  label?: string;
  weight: number;
}

export interface Graph {
  nodes: Node[];
  edges: Edge[];
}

import { Command } from "commander";
import chalk from "chalk";
import { load, addNode, link, removeNode, exportMarkdown, graphStats, mostConnectedNode, listNodeTitles } from "./store/graph.js";

const program = new Command()
  .name("carto")
  .description("Terminal knowledge-map — link ideas, export to markdown")
  .version("0.1.0");

program
  .command("add <title>")
  .description("Add a new node to the map")
  .option("-b, --body <text>", "Node content", "")
  .option("-t, --tags <tags>", "Comma-separated tags", "")
  .action((title: string, opts: { body: string; tags: string }) => {
    const node = addNode(title, opts.body, opts.tags ? opts.tags.split(",") : []);
    console.log(chalk.green(`✓ Added: ${node.title} [${node.id.slice(0, 8)}]`));
  });

program
  .command("rm <title>")
  .description("Remove a node and all its edges from the map")
  .action((title: string) => {
    const result = removeNode(title);
    if (result) {
      console.log(chalk.green(`✓ Removed "${title}" and ${result.edgeCount} edge(s)`));
    } else {
      console.error(chalk.red(`✗ Node not found: "${title}"`));
      process.exit(1);
    }
  });

program
  .command("link <from> <to>")
  .description("Connect two nodes")
  .option("-l, --label <label>", "Edge label")
  .action((from: string, to: string, opts: { label?: string }) => {
    try {
      link(from, to, opts.label);
      console.log(chalk.cyan(`→ Linked "${from}" → "${to}"`));
    } catch (e) {
      console.error(chalk.red(String(e)));
    }
  });

program
  .command("list")
  .description("List all nodes")
  .action(() => {
    const { nodes } = load();
    if (!nodes.length) { console.log("No nodes yet. Try: carto add \"My first idea\""); return; }
    for (const n of nodes) {
      console.log(chalk.bold(n.title), chalk.gray(`[${n.id.slice(0, 8)}]`), n.tags.map((t) => chalk.yellow(`#${t}`)).join(" "));
    }
  });

program
  .command("ls")
  .description("List all node titles")
  .action(() => {
    const titles = listNodeTitles();
    if (!titles.length) {
      console.log(chalk.yellow("No nodes yet."));
      return;
    }
    for (const title of titles) {
      console.log(chalk.cyan(title));
    }
  });

program
  .command("export")
  .description("Export the map to markdown")
  .action(() => {
    console.log(exportMarkdown());
  });

program
  .command("stats")
  .description("Show graph statistics")
  .action(() => {
    const graph = load();
    const { nodes, edges } = graphStats(graph);
    console.log(chalk.green(`${nodes} ${nodes === 1 ? "node" : "nodes"}, ${edges} ${edges === 1 ? "edge" : "edges"}`));
    const { node, degree } = mostConnectedNode(graph);
    if (node) {
      console.log(chalk.cyan(`Most connected: ${node.title} (degree ${degree})`));
    } else {
      console.log(chalk.gray("(no edges)"));
    }
  });

program.parse();

import { randomUUID } from "crypto";
import { readFileSync, writeFileSync, existsSync, mkdirSync } from "fs";
import { join } from "path";
import type { Graph, Node, Edge } from "../types.js";

const DATA_PATH = join(process.env.HOME ?? "~", ".cartographer", "graph.json");

function load(): Graph {
  if (!existsSync(DATA_PATH)) return { nodes: [], edges: [] };
  return JSON.parse(readFileSync(DATA_PATH, "utf8")) as Graph;
}

function save(graph: Graph): void {
  const dir = join(process.env.HOME ?? "~", ".cartographer");
  mkdirSync(dir, { recursive: true });
  writeFileSync(DATA_PATH, JSON.stringify(graph, null, 2));
}

export function addNode(title: string, body: string, tags: string[]): Node {
  const graph = load();
  const node: Node = {
    id: randomUUID(),
    title,
    body,
    tags,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  graph.nodes.push(node);
  save(graph);
  return node;
}

export function link(fromTitle: string, toTitle: string, label?: string): Edge {
  const graph = load();
  const from = graph.nodes.find((n) => n.title === fromTitle);
  const to = graph.nodes.find((n) => n.title === toTitle);
  if (!from || !to) throw new Error(`Node not found`);
  const edge: Edge = { from: from.id, to: to.id, label, weight: 1 };
  graph.edges.push(edge);
  save(graph);
  return edge;
}

export function removeNode(title: string): { node: Node; edgeCount: number } | null {
  const graph = load();
  const node = graph.nodes.find((n) => n.title === title);
  if (!node) return null;
  graph.nodes = graph.nodes.filter((n) => n.id !== node.id);
  const removedEdges = graph.edges.filter((e) => e.from === node.id || e.to === node.id);
  graph.edges = graph.edges.filter((e) => e.from !== node.id && e.to !== node.id);
  save(graph);
  return { node, edgeCount: removedEdges.length };
}

export function exportMarkdown(): string {
  const graph = load();
  const lines: string[] = ["# Knowledge Map\n"];
  for (const node of graph.nodes) {
    lines.push(`## ${node.title}`);
    if (node.tags.length) lines.push(`*tags: ${node.tags.join(", ")}*\n`);
    lines.push(node.body);
    const outgoing = graph.edges.filter((e) => e.from === node.id);
    if (outgoing.length) {
      lines.push("\n**Links:**");
      for (const edge of outgoing) {
        const target = graph.nodes.find((n) => n.id === edge.to);
        if (target) lines.push(`- → [${target.title}]${edge.label ? ` *(${edge.label})*` : ""}`);
      }
    }
    lines.push("");
  }
  return lines.join("\n");
}

export function graphStats(graph: Graph): { nodes: number; edges: number } {
  return { nodes: graph.nodes.length, edges: graph.edges.length };
}

export function listNodeTitles(): string[] {
  const graph = load();
  return graph.nodes.map((n) => n.title);
}

export function mostConnectedNode(graph: Graph): { node: Node | null; degree: number } {
  if (graph.edges.length === 0) {
    return { node: null, degree: 0 };
  }

  const degreeMap = new Map<string, number>();

  for (const edge of graph.edges) {
    // Bidirectional degree: each edge contributes +1 to both nodes
    // regardless of direction, counting both as connected
    degreeMap.set(edge.from, (degreeMap.get(edge.from) ?? 0) + 1);
    degreeMap.set(edge.to, (degreeMap.get(edge.to) ?? 0) + 1);
  }

  let maxDegree = -1;
  let maxNode: Node | null = null;

  for (const node of graph.nodes) {
    const degree = degreeMap.get(node.id) ?? 0;
    if (degree > maxDegree) {
      maxDegree = degree;
      maxNode = node;
    }
  }

  return { node: maxNode, degree: maxDegree };
}

export { load, save };

{
  "name": "cartographer",
  "version": "0.1.0",
  "description": "Terminal knowledge-map tool — link ideas, export to markdown",
  "type": "module",
  "bin": {
    "carto": "./dist/cli.js"
  },
  "scripts": {
    "build": "tsc",
    "dev": "tsx src/cli.ts",
    "test": "vitest run",
    "lint": "eslint src"
  },
  "dependencies": {
    "chalk": "^5.3.0",
    "commander": "^11.1.0",
    "enquirer": "^2.4.1",
    "ink": "^4.4.1",
    "lowdb": "^7.0.1",
    "react": "^18.2.0"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/react": "^18.0.0",
    "@typescript-eslint/eslint-plugin": "^8.60.0",
    "@typescript-eslint/parser": "^8.60.0",
    "eslint": "^10.4.1",
    "tsx": "^4.0.0",
    "typescript": "^5.3.0",
    "vitest": "^1.0.0"
  }
}

{
  "compilerOptions": {
    "target": "ES2022",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "outDir": "dist",
    "rootDir": "src",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true
  },
  "include": ["src"]
}

import { describe, it, expect, vi, beforeEach } from "vitest";
import * as fs from "fs";
import { join } from "path";
import { save, addNode, link, load, exportMarkdown, graphStats, mostConnectedNode } from "../store/graph.js";

vi.mock("fs", async (importOriginal) => {
  const actual = await importOriginal<typeof import("fs")>();
  return {
    ...actual,
    mkdirSync: vi.fn(),
    writeFileSync: vi.fn(),
    readFileSync: vi.fn(() => JSON.stringify({ nodes: [], edges: [] })),
    existsSync: vi.fn(() => true),
  };
});

vi.mock("crypto", () => ({
  randomUUID: vi.fn(() => "test-uuid-00000000"),
}));

describe("save()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("calls mkdirSync before writeFileSync", () => {
    const graph = { nodes: [], edges: [] };
    save(graph);

    const mockedFs = vi.mocked(fs);
    expect(mockedFs.mkdirSync).toHaveBeenCalledWith(
      expect.stringContaining(".cartographer"),
      { recursive: true },
    );
    expect(mockedFs.writeFileSync).toHaveBeenCalled();
    // mkdirSync must be called before writeFileSync
    const mkdirCall = mockedFs.mkdirSync.mock.invocationCallOrder[0];
    const writeCall = mockedFs.writeFileSync.mock.invocationCallOrder[0];
    expect(mkdirCall).toBeLessThan(writeCall);
  });

  it("always calls mkdirSync even when directory exists", () => {
    const graph = { nodes: [], edges: [] };
    save(graph);

    const mockedFs = vi.mocked(fs);
    expect(mockedFs.mkdirSync).toHaveBeenCalledTimes(1);
  });

  it("calls mkdirSync with the correct directory path", () => {
    const graph = { nodes: [], edges: [] };
    save(graph);

    const mockedFs = vi.mocked(fs);
    expect(mockedFs.mkdirSync).toHaveBeenCalledWith(
      join(process.env.HOME ?? "~", ".cartographer"),
      { recursive: true },
    );
  });
});

describe("addNode()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("creates a node with the given title and tags", () => {
    const node = addNode("Test Idea", "Some body", ["tag1"]);

    expect(node.title).toBe("Test Idea");
    expect(node.body).toBe("Some body");
    expect(node.tags).toEqual(["tag1"]);
    expect(node.id).toBe("test-uuid-00000000");
  });
});

describe("link()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("throws when source node does not exist", () => {
    expect(() => link("Missing", "Also Missing")).toThrow("Node not found");
  });

  it("returns Edge with correct from/to IDs when both nodes exist", () => {
    const handcrafted = {
      nodes: [
        { id: "id-a", title: "Node A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Node B", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(handcrafted));

    const edge = link("Node A", "Node B");
    expect(edge.from).toBe("id-a");
    expect(edge.to).toBe("id-b");
    expect(edge.from).not.toBe(edge.to);
  });

  it("returns edge without label having label undefined and weight 1", () => {
    const handcrafted = {
      nodes: [
        { id: "id-a", title: "Node A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Node B", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(handcrafted));

    const edge = link("Node A", "Node B");
    expect(edge.label).toBeUndefined();
    expect(edge.weight).toBe(1);
  });

  it("returns edge with label carrying the label string", () => {
    const handcrafted = {
      nodes: [
        { id: "id-a", title: "Node A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Node B", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(handcrafted));

    const edge = link("Node A", "Node B", "depends on");
    expect(edge.label).toBe("depends on");
    expect(edge.weight).toBe(1);
  });
});

describe("load()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("returns empty graph when file does not exist", () => {
    const mockedFs = vi.mocked(fs);
    mockedFs.existsSync.mockReturnValueOnce(false);

    const graph = load();
    expect(graph).toEqual({ nodes: [], edges: [] });
  });

  it("returns populated Graph when file exists with valid JSON", () => {
    const populated = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "Body A", tags: ["t1"], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Beta", body: "Body B", tags: ["t2", "t3"], createdAt: "2025-01-02T00:00:00.000Z", updatedAt: "2025-01-02T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: "related", weight: 1 },
      ],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(populated));

    const graph = load();
    expect(graph.nodes).toHaveLength(2);
    expect(graph.edges).toHaveLength(1);
    expect(graph.edges[0].from).toBe("id-a");
    expect(graph.edges[0].to).toBe("id-b");
  });
});

describe("exportMarkdown()", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("produces '# Knowledge Map' header as first line", () => {
    vi.mocked(fs).readFileSync.mockReturnValueOnce(
      JSON.stringify({ nodes: [], edges: [] }),
    );
    const md = exportMarkdown();
    expect(md.split("\n")[0]).toBe("# Knowledge Map");
  });

  it("renders each node with title, tags, and body", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "Body text", tags: ["t1", "t2"], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();
    expect(md).toContain("## Alpha");
    expect(md).toContain("*tags: t1, t2*");
    expect(md).toContain("Body text");
  });

  it("renders outgoing links when edges exist", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "A body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Beta", body: "B body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: undefined, weight: 1 },
      ],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();
    expect(md).toContain("**Links:**");
    expect(md).toContain("→ [Beta]");
  });

  it("omits links section when node has no outgoing edges", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "A body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();
    expect(md).not.toContain("**Links:**");
  });

  it("renders edge label when provided", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "A body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Beta", body: "B body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: "depends on", weight: 1 },
      ],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();
    expect(md).toContain("*(depends on)*");
    expect(md).toContain("→ [Beta]");
  });

  it("renders edge without label as plain link", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "A body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Beta", body: "B body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: undefined, weight: 1 },
      ],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();
    const linkLine = md.split("\n").find((l) => l.includes("→ [Beta]"));
    expect(linkLine).toBeDefined();
    // Plain link: no label parenthetical after the target title
    expect(linkLine).not.toContain("*(");
  });

  it("renders **Links:** under source node only, not target node", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Alpha", body: "A body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Beta", body: "B body", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: undefined, weight: 1 },
      ],
    };
    vi.mocked(fs).readFileSync.mockReturnValueOnce(JSON.stringify(graph));
    const md = exportMarkdown();

    // Partition output into sections by ## NodeTitle headers
    const sections = md.split(/(?=^## )/m).filter((s) => s.trim());
    const alphaSection = sections.find((s) => s.startsWith("## Alpha")) ?? "";
    const betaSection = sections.find((s) => s.startsWith("## Beta")) ?? "";

    // Source (Alpha) must have Links block
    expect(alphaSection).toContain("**Links:**");
    expect(alphaSection).toContain("→ [Beta]");

    // Target (Beta) must NOT have Links block — edge direction is one-way (from, not to)
    expect(betaSection).not.toContain("**Links:**");
    expect(betaSection).not.toContain("→ [Beta]");
  });
});

describe("save() content verification", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("writes JSON stringified graph containing nodes and edges arrays", () => {
    const graph = {
      nodes: [
        { id: "id-x", title: "X", body: "Body X", tags: ["t1"], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-x", to: "id-y", label: "ref", weight: 1 },
      ],
    };
    save(graph);
    const written = vi.mocked(fs).writeFileSync.mock.calls[0][1] as string;
    const parsed = JSON.parse(written);
    expect(parsed).toHaveProperty("nodes");
    expect(parsed).toHaveProperty("edges");
    expect(parsed.nodes).toHaveLength(1);
    expect(parsed.edges).toHaveLength(1);
  });

  it("serialized graph contains correct node fields", () => {
    const node = {
      id: "id-1",
      title: "TestNode",
      body: "Some body",
      tags: ["a", "b"],
      createdAt: "2025-06-01T00:00:00.000Z",
      updatedAt: "2025-06-01T00:00:00.000Z",
    };
    const graph = { nodes: [node], edges: [] };
    save(graph);
    const written = vi.mocked(fs).writeFileSync.mock.calls[0][1] as string;
    const parsed = JSON.parse(written);
    const savedNode = parsed.nodes[0];
    expect(savedNode.id).toBe("id-1");
    expect(savedNode.title).toBe("TestNode");
    expect(savedNode.body).toBe("Some body");
    expect(savedNode.tags).toEqual(["a", "b"]);
    expect(savedNode.createdAt).toBe("2025-06-01T00:00:00.000Z");
    expect(savedNode.updatedAt).toBe("2025-06-01T00:00:00.000Z");
  });
});

describe("graphStats()", () => {
  it("returns { nodes: 2, edges: 1 } for a 2-node/1-edge graph", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "Node A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
        { id: "id-b", title: "Node B", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [
        { from: "id-a", to: "id-b", label: undefined, weight: 1 },
      ],
    };
    expect(graphStats(graph)).toEqual({ nodes: 2, edges: 1 });
  });

  it("returns { nodes: 0, edges: 0 } for an empty graph", () => {
    const graph = { nodes: [], edges: [] };
    expect(graphStats(graph)).toEqual({ nodes: 0, edges: 0 });
  });
});

describe("mostConnectedNode()", () => {
  it("returns { node: null, degree: 0 } sentinel when no edges exist", () => {
    const graph = {
      nodes: [
        { id: "id-a", title: "A", body: "", tags: [], createdAt: "2025-01-01T00:00:00.000Z", updatedAt: "2025-01-01T00:00:00.000Z" },
      ],
      edges: [],
    };
